questionvariables.text:
/* Base triangle */
Ax: -3;
Ay: 1;

Bx: -1;
By: 4;

Cx: 2;
Cy: 2;

/* Random translation */
tx: rand(4) + 3;
ty: rand(4) - 2;

/* Mode selector
   0 = translation
   1 = rotation + translation
   2 = not congruent
*/
mode: rand(3);

/* Image triangle */
if mode=0 then (
    Sx: Ax+tx,  Sy: Ay+ty,
    Tx: Bx+tx,  Ty: By+ty,
    Vx: Cx+tx,  Vy: Cy+ty
)
elseif mode=1 then (
    Sx: -Ax+tx,  Sy: -Ay+ty,
    Tx: -Bx+tx,  Ty: -By+ty,
    Vx: -Cx+tx,  Vy: -Cy+ty
)
else (
    /* Not congruent */
    Sx: Ax+tx,  Sy: 2*Ay+ty,
    Tx: Bx+tx,  Ty: 2*By+ty,
    Vx: Cx+tx,  Vy: 2*Cy+ty
);

/* Congruence flag */
is_cong: if mode=2 then false else true;

/* Part (a) permutation */
ta_cong_opts:
    random_permutation([
        ["Yes", is_cong],
        ["No", not is_cong]
    ]);

/* Part (b) correct transformation */
ta_trans:
    if mode=0 then "translation"
    elseif mode=1 then "rotation and translation"
    else "not possible";

/* Part (b) permutation */
ta_trans_opts:
    random_permutation([
        ["Translation", is(ta_trans="translation")],
        ["Rotation and translation", is(ta_trans="rotation and translation")],
        ["Not possible", is (ta_trans="not possible")]
    ]);

feedbackvariables.text:
/* Convert yes/no text answer into numeric value */
ans1n:
  if is(ans1 = "yes") or is(ans1 = "Yes") or is(ans1 = "YES") then 1
  elseif is(ans1 = "no") or is(ans1 = "No") or is(ans1 = "NO") then 0
  else -1;
